option.value:
body {
    background-color: #292831 !important;
    color: #d8ded6 !important;
}
pre, code {
    background-color: #2c2f3d !important;
    color: #b1bdb2 !important;
}
blockquote {
    background-color: #2c2f3d !important;
    color: #d8ded6 !important;
    border-left: 4px solid #3a3149 !important;
}

blockquote pre, blockquote code {
    background-color: #292831 !important;
}
